Code.Terraform:
```hcl
# Terraform: Create a SageMaker Domain with SSO authentication
resource "aws_sagemaker_domain" "example" {
  domain_name = "<example_domain_name>"
  auth_mode   = "SSO"  # Critical: enables IAM Identity Center authentication
  vpc_id      = "<example_vpc_id>"
  subnet_ids  = ["<example_subnet_id>"]

  default_user_settings {
    execution_role = "<example_role_arn>"
  }
}
```
